document.addEventListener('DOMContentLoaded', function () {

  /* ==============================
     VARIABLES
  ============================== */
  var calendarEl = document.getElementById('calendar');
  var form = document.getElementById('eventForm');

  var eventModalEl = document.getElementById('eventModal');
  var eventModal = new bootstrap.Modal(eventModalEl);

  var today = new Date().toISOString().split('T')[0];
  const token = getCookie('token');


  /* ==============================
     FULLCALENDAR INIT
  ============================== */
  var calendar = new FullCalendar.Calendar(calendarEl, {
    headerToolbar: {
      left: 'prev,next today',
      center: 'title',
      right: 'dayGridMonth,timeGridWeek,timeGridDay'
    },
    initialDate: today,
    locale: 'es',
    navLinks: true,
    selectable: true,
    selectMirror: true,
    editable: true,
    dayMaxEvents: true,
    events: [],

    /* ==============================
       SELECCIÓN DE FECHA
    ============================== */
    select: function (arg) {

      var selectedDate = arg.startStr.split('T')[0];

      if (selectedDate < today) {
        alert("No se pueden crear actividades para fechas anteriores a la actual.");
        calendar.unselect();
        return;
      }

      document.getElementById('endDate').value = selectedDate;

      eventModal.show();
    },

    /* ==============================
       CLICK EN EVENTO
    ============================== */
    eventClick: function (arg) {

      const activityId = arg.event.extendedProps.numero_actividad;
      localStorage.setItem('activityId', activityId);

    }
  });

  calendar.render();


  /* ==============================
     CARGAR EVENTOS DESDE API
  ============================== */
  function loadEvents() {

    fetch(`${ENV.API_URL}/activity`, {
      method: 'GET',
      headers: {
        'Authorization': `Bearer ${token}`,
        'Content-Type': 'application/json'
      }
    })
      .then(response => response.json())
      .then(data => {

        const events = data.data.map(activity => {

          const start = new Date(activity.inicio_actividad);
          const end = new Date(activity.fin_actividad);

          return {
            title: activity.nombre_actividad,
            start: start.toISOString().split('.')[0],
            end: end.toISOString().split('.')[0],
            backgroundColor: '#0081cc',
            extendedProps: {
              numero_actividad: activity.numero_actividad
            }
          };
        });

        calendar.addEventSource(events);
      })
      .catch(error => {
        MessageEvent.show("Hola");
      });
  }

  loadEvents();


  /* ==============================
     GUARDAR EVENTO
  ============================== */
  form.addEventListener('submit', function (e) {
    e.preventDefault();

    const nombre = document.getElementById('nombre_actividad').value.trim();
    const punteo = document.getElementById('punteo').value;
    const descripcion = document.getElementById('descripcion').value;
    const endDate = document.getElementById('endDate').value;

    if (!nombre || !punteo || !endDate) {
      toastr.warning("Complete los campos obligatorios");
      return;
    }

    const newEvent = {
      title: nombre,
      start: endDate,
      end: endDate,
      allDay: true
    };

    // Agregar visualmente al calendario
    calendar.addEvent(newEvent);

    toastr.success("Actividad agregada correctamente");

    eventModal.hide();
  });


  /* ==============================
     RESET AUTOMÁTICO AL CERRAR
  ============================== */
  eventModalEl.addEventListener('hidden.bs.modal', function () {
    form.reset();
    calendar.unselect();
  });

});


/* ==============================
   GET COOKIE
============================== */
function getCookie(name) {
  const value = `; ${document.cookie}`;
  const parts = value.split(`; ${name}=`);
  if (parts.length === 2)
    return parts.pop().split(';').shift();
}
